args.sparql:
SELECT ?country ?countryLabel ?area WHERE {
  ?country wdt:P31 wd:Q6256 ;
           wdt:P30 wd:Q46 ;
           wdt:P2046 ?area .
  ?country rdfs:label ?countryLabel .
  FILTER (LANG(?countryLabel) = 'en')
} ORDER BY DESC(?area) LIMIT 2

